INSERT INTO `lostnfound` VALUES ('4','1','4','Gesucht','Christina Bornholt','gesucht wird das Heiratsdatum und Todesdatum der Obengenannten\n\ngeboren 28 Mai 1803 &bull; Altenfelsdeich Seester\n\ngeheiratet 26 Sep 1823 &bull; Uetersen Peter Meyn\n\nnach dem Tod des 1 ten Ehemann 1854 heiratet sie in Appen einen Hr. Heitmann und verstarb in Appen\n\nDie Informationen &uuml;ber ihre 2 te Ehe  stammen aus der Sterbeurkunde ihrer Tochter Christina','1529242904','1529242904');

