DROP TABLE IF EXISTS `texts`;
CREATE TABLE `texts` (
  `id` bigint(11) NOT NULL AUTO_INCREMENT,
  `pub` tinyint(2) NOT NULL,
  `position` bigint(11) NOT NULL,
  `headline` varchar(80) DEFAULT NULL,
  `text` text NOT NULL,
  `autoslug` varchar(50) NOT NULL,
  `users_id` varchar(100) NOT NULL,
  `created_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

INSERT INTO `texts` VALUES ('9','1','6','Künstliche Intelligenz Bei MonikaDargies.de','<p>Bildgenerierende KIs öffnen Türen, von denen wir lange nicht wussten, dass sie da sind. Sie nehmen ein paar Worte, schlicht wie Kieselsteine in der Hand, und formen daraus Bilder, die größer wirken als das, was man hineingelegt hat. Sie tun es ohne Zittern, ohne Zweifel, nur mit der stillen Genauigkeit einer Maschine, die gelernt hat, die Welt auf ihre Weise zu sehen.</p><p><br /></p><p>Man gibt ihnen eine Beschreibung, ein Gefühl, einen Gedanken. Und sie antworten mit Farben, mit Licht, mit Formen, die manchmal fremd wirken und manchmal erstaunlich vertraut. In Kunst, im Design, im Marketing – überall dort, wo Menschen Bilder brauchen – sind diese neuen Werkzeuge angekommen wie ein frischer Wind, der keine Erlaubnis braucht.</p><p><br /></p><p>Die Bilder, die mit „AI“ markiert sind, wurden mit NightCafe Studio geschaffen. Manche wurden danach weiter verfeinert, wie man ein Messer nachschärft, obwohl es schon gut schneidet. Doch der erste Schlag, die erste Kontur, stammt von der Maschine.</p>','ai','1','2024-10-21 09:55:17');
INSERT INTO `texts` VALUES ('12','1','5','Sie haben nicht die benötigten Rechte','<p>Diese Seite wurde gesperrt.<br /><br /><br /><br /><br />Wenden Sie sich an den Administrator falls Sie diese Funktion benötigen</p><p>Kontakt hier: <a href=\"http://www.marblefx.net/home/contacts\">http://www.marblefx.net/home/contacts</a></p>','no-rights','1','2024-10-21 12:29:42');
INSERT INTO `texts` VALUES ('16','1','2','Kontakt','<div><strong>Wir freuen uns, von Ihnen zu hören!</strong><br /></div><div>Ob Fragen, Feedback oder ein konkretes Anliegen – Asario steht Ihnen jederzeit zur Verfügung.</div><div>Nutzen Sie gerne die untenstehenden Kontaktdaten oder senden Sie uns direkt eine Nachricht</div><div>über das Kontaktformular.</div>','ContactsHeader','1','2025-08-10 11:16:51');
INSERT INTO `texts` VALUES ('17','1','3','Kontaktdaten','<div>Monika Dargies</div><div>Schäferberg 8b</div><div>24576 Bad Bramstedt</div><div>Tel: <a href=\"tel:041928140467\">04192/8140467</a></div><div>email: <a href=\"mailto:matotap@gmx.de\">matotap%5Bat%5Dgmx.de</a></div><div></div>','ContactsInfos','1','2025-08-10 11:34:24');
INSERT INTO `texts` VALUES ('18','1','4','Willkommen liebe Besucher','<div>Mein Name ist Monika Dargies, geb.Mai, komme aus Bad Bramstedt und betreibe Familienforschung seit 2005.</div><div><br /></div><div>Die genealogischen Informationen dieser Homepage werden privat zusammengetragen und ich bitte darum, dass diese nicht einfach nur abgeschrieben werden. Ich freue mich über jeden, der mir eine Email schreibt zwecks Datenaustausch.</div><div><br /></div><div>Meine Vorfahren stammen väterlicherseits \"Mai\" aus Schlesien, \"Williges\" aus Helsa und mütterlicherseits \"Hagemann\" aus Vorpommern, \"Meyn\" aus Haseldorfer Marsch. Des Weiteren ist die Familie meines Mannes Dargies/Fago aus Ostpreussen vertreten.</div><div><br /></div><div>Ein besonderer Dank gilt Asario, der diese Website für mich erstellt hat.</div>','dag_home','1','2025-09-23 12:01:53');
INSERT INTO `texts` VALUES ('19','1','1','131102','13313','yvut','1','2025-12-13 12:48:41');

DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `pub` tinyint(1) NOT NULL DEFAULT 0,
  `users_rights_id` tinyint(1) NOT NULL DEFAULT 5,
  `name` varchar(50) DEFAULT NULL,
  `nick_name` varchar(150) DEFAULT NULL,
  `password` varchar(255) NOT NULL,
  `password_old` varchar(155) DEFAULT NULL,
  `email` varchar(90) DEFAULT NULL,
  `first_name` varchar(30) DEFAULT NULL,
  `music` varchar(255) DEFAULT NULL,
  `birthday` date DEFAULT NULL,
  `fbd` varchar(120) DEFAULT NULL,
  `website` varchar(255) DEFAULT NULL,
  `occupation` varchar(255) DEFAULT NULL,
  `email_verified_at` datetime DEFAULT NULL,
  `interests` varchar(255) DEFAULT NULL,
  `about` mediumtext DEFAULT NULL,
  `about_en` mediumtext DEFAULT NULL,
  `xis_disabled` tinyint(1) DEFAULT NULL,
  `xis_aiImage` tinyint(2) DEFAULT NULL,
  `last_login_at` timestamp NULL DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `is_admin` tinyint(1) DEFAULT NULL,
  `is_employee` tinyint(1) DEFAULT NULL,
  `is_customer` tinyint(1) DEFAULT NULL,
  `remember_token` varchar(255) DEFAULT NULL,
  `two_factor_secret` varchar(255) DEFAULT NULL,
  `two_factor_recovery_codes` text DEFAULT NULL,
  `two_factor_confirmed_at` datetime DEFAULT NULL,
  `two_factor_enabled` tinyint(2) DEFAULT NULL,
  `profile_photo_path` varchar(150) DEFAULT NULL,
  `uhash` varchar(255) NOT NULL,
  `updated_at` datetime DEFAULT NULL,
  `google_id` text DEFAULT '',
  PRIMARY KEY (`id`),
  UNIQUE KEY `nick` (`name`),
  UNIQUE KEY `email` (`email`)
) ENGINE=MyISAM AUTO_INCREMENT=394 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci PACK_KEYS=0;


DROP TABLE IF EXISTS `users_config`;
CREATE TABLE `users_config` (
  `id` bigint(11) NOT NULL AUTO_INCREMENT,
  `pub` tinyint(1) NOT NULL DEFAULT 1,
  `users_id` bigint(11) NOT NULL DEFAULT 0,
