  `xkis_AdminPanel` tinyint(2) DEFAULT NULL,
  `xkis_ChangePassword` tinyint(1) NOT NULL DEFAULT 0,
  `xkis_CommentsCenter` tinyint(1) NOT NULL DEFAULT 0,
